#!/usr/bin/env python3
"""
WSTI Quiz - a free, self-hosted Kahoot-style live quiz.
Runs on your laptop using only Python's standard library (no installs).
Players join by scanning a QR code on the big screen.

If 'cloudflared' is installed and this laptop has internet, a free public link
is created automatically so phones can join from ANY network (mobile data too).
Otherwise it falls back to same-Wi-Fi only. Disable the tunnel with QUIZ_NO_TUNNEL=1.

Big screen  ->  http://localhost:8000/host
Phones      ->  the QR / link shown on the big screen
"""

import json
import os
import queue
import socket
import threading
import time
import re
import shutil
import atexit
import subprocess
import http.server
import socketserver
from urllib.parse import urlparse, parse_qs

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
# On a cloud host (Render/Railway/Heroku/etc.) the platform sets $PORT and gives
# us a public URL — so we bind that exact port and skip the local tunnel.
# Locally, nothing changes: we use QUIZ_PORT or 8000 and create a tunnel.
_PLATFORM_PORT = os.environ.get("PORT")
ON_PLATFORM = bool(_PLATFORM_PORT)
PORT = int(_PLATFORM_PORT or os.environ.get("QUIZ_PORT", "8000"))

# Set once a Cloudflare quick tunnel is up, so phones can join from ANY network
# (mobile data, a different Wi-Fi) — not just the same Wi-Fi as this laptop.
PUBLIC_URL = None
_tunnel_proc = None

import base64 as _b64
_EMBEDDED = {
    "host.html": "",
    "player.html": "",
}

# ----------------------------------------------------------------------------
# Questions (colors: 0=red/triangle, 1=blue/diamond, 2=yellow/circle, 3=green/square)
# ----------------------------------------------------------------------------
QUESTIONS = [
    {"type": "mc", "time": 15, "emoji": "🤖", "text": "What does AI stand for?",
     "options": ["Artificial Intelligence", "Absolutely Incredible", "Almost Instagram", "Auntie Indu"],
     "correct": 0},
    {"type": "mc", "time": 15, "emoji": "🧠", "text": "How does AI learn best?",
     "options": ["Asking Google", "Data", "Magic", "Dreaming"],
     "correct": 1},
    {"type": "mc", "time": 15, "emoji": "🤝", "text": "What does Cowork with Claude mean?",
     "options": ["Steals your job", "Works with you", "Free snacks", "Office gossip"],
     "correct": 1},
    {"type": "mc", "time": 15, "emoji": "🔌", "text": "Which app can Claude NOT connect?",
     "options": ["Gmail", "Calendar", "Your toaster", "Drive"],
     "correct": 2},
    {"type": "mc", "time": 15, "emoji": "🌀", "text": "“Hallucination” in AI means…?",
     "options": ["Saw a ghost", "It is dreaming", "It is tired", "It made something up"],
     "correct": 3},
    {"type": "mc", "time": 15, "emoji": "🧭", "text": "AI without context is like what?",
     "options": ["A toaster", "A superhero", "A newborn", "A calculator"],
     "correct": 2},
    {"type": "mc", "time": 15, "emoji": "🛠️", "text": "What describes a Claude Skill?",
     "options": ["Reusable recipe", "Secret handshake", "Talent show", "New emoji"],
     "correct": 0},
    {"type": "mc", "time": 15, "emoji": "⚙️", "text": "Agents in Claude are like what?",
     "options": ["Parking inspectors", "Detective Agents", "Secret spies", "Little helpers with specific jobs"],
     "correct": 3},
    {"type": "mc", "time": 15, "emoji": "🔗", "text": "Connectors are like what?",
     "options": ["Bluetooth speakers", "Bridges to apps", "Cup noodles", "Headphones"],
     "correct": 1},
    {"type": "mc", "time": 15, "emoji": "🚀", "text": "How should you learn about agents?",
     "options": ["Copy neighbour", "Play and experiment", "Wait for magic", "Stare at screen"],
     "correct": 1},
    {"type": "open", "time": 30, "emoji": "🎭", "text": "What’s the weirdest or funniest thing we can’t do with AI (yet)?",
     "options": [], "correct": None},
]

OPEN_POINTS = 500  # flat points awarded for submitting an open-ended answer

# How long the combined results screen stays up before auto-advancing (ms)
MC_RESULTS_MS = 8000      # multiple-choice results
OPEN_RESULTS_MS = 12000   # open-ended results (more to read)

# ----------------------------------------------------------------------------
# Game state
# ----------------------------------------------------------------------------
class Game:
    def __init__(self):
        self.lock = threading.RLock()
        self.players = {}      # id -> {name, score, answered, lastGain, answerIdx}
        self.subscribers = []  # list of {q: Queue, role, id}
        self.phase = "lobby"   # lobby | question | reveal | podium
        self.qIndex = -1
        self.startTime = 0     # ms when current question began
        self.revealTime = 0    # ms when the current results screen began (for auto-advance)
        self.paused = False    # when True, the results screen won't auto-advance
        self.answers = {}      # id -> {idx/text, t (ms used), correct, points}
        self.open_responses = []

    # -- subscriber management --
    def subscribe(self, role, pid):
        q = queue.Queue()
        sub = {"q": q, "role": role, "id": pid}
        with self.lock:
            self.subscribers.append(sub)
        return sub

    def unsubscribe(self, sub):
        with self.lock:
            if sub in self.subscribers:
                self.subscribers.remove(sub)

    def broadcast(self):
        with self.lock:
            subs = list(self.subscribers)
        for sub in subs:
            try:
                sub["q"].put_nowait(self.state_for(sub["id"]))
            except Exception:
                pass

    # -- public state sent to a given client --
    def state_for(self, pid):
        with self.lock:
            now = int(time.time() * 1000)
            board = sorted(
                ({"name": p["name"], "score": p["score"], "correct": p.get("nCorrect", 0),
                  "avg": (round(p["tSum"] / p["nCorrect"] / 1000.0, 1) if p.get("nCorrect") else None)}
                 for p in self.players.values()),
                key=lambda x: -x["score"],
            )
            st = {
                "phase": self.phase,
                "qIndex": self.qIndex,
                "total": len(QUESTIONS),
                "now": now,
                "startTime": self.startTime,
                "paused": self.paused,
                "playerCount": len(self.players),
                "answeredCount": len(self.answers),
                "board": board,
            }
            q = None
            if 0 <= self.qIndex < len(QUESTIONS):
                Q = QUESTIONS[self.qIndex]
                q = {
                    "type": Q["type"],
                    "text": Q["text"],
                    "emoji": Q.get("emoji", ""),
                    "options": Q["options"],
                    "time": Q["time"],
                    "optionCount": len(Q["options"]),
                }
                if self.phase in ("reveal", "podium"):
                    q["correct"] = Q["correct"]
            st["question"] = q

            if self.phase == "reveal" and q is not None:
                st["revealTime"] = self.revealTime
                st["resultsDurMs"] = self.results_duration()
                if QUESTIONS[self.qIndex]["type"] == "mc":
                    counts = [0, 0, 0, 0]
                    correct_order = []
                    for aid, a in self.answers.items():
                        if isinstance(a.get("idx"), int) and 0 <= a["idx"] < 4:
                            counts[a["idx"]] += 1
                        if a.get("correct"):
                            correct_order.append({
                                "name": self.players.get(aid, {}).get("name", "?"),
                                "t": round(a["t"] / 1000.0, 1),
                            })
                    correct_order.sort(key=lambda x: x["t"])
                    st["counts"] = counts
                    st["correctCount"] = len(correct_order)
                    st["fastestOrder"] = correct_order
                else:
                    st["openResponses"] = list(self.open_responses)

            # per-player info
            you = None
            if pid in self.players:
                p = self.players[pid]
                you = {
                    "name": p["name"],
                    "answered": pid in self.answers,
                    "correct": self.answers.get(pid, {}).get("correct") if pid in self.answers else None,
                    "nCorrect": p.get("nCorrect", 0),
                    "avg": (round(p["tSum"] / p["nCorrect"] / 1000.0, 1) if p.get("nCorrect") else None),
                }
                # overall rank (by internal speed-score; numbers never shown to players)
                names = [b["name"] for b in board]
                if p["name"] in names:
                    you["rank"] = names.index(p["name"]) + 1
                # per-question speed rank among correct answerers (for the reveal screen)
                if self.phase == "reveal" and pid in self.answers and self.answers[pid].get("correct"):
                    mine = self.answers[pid]["t"]
                    faster = sum(1 for a in self.answers.values()
                                 if a.get("correct") and a["t"] < mine)
                    you["speedRank"] = faster + 1
                    you["correctTotal"] = sum(1 for a in self.answers.values() if a.get("correct"))
            st["you"] = you
            return st

    # -- player actions --
    def join(self, name):
        name = (name or "").strip()[:20] or "Player"
        pid = "p" + str(int(time.time() * 1000)) + str(len(self.players))
        with self.lock:
            # de-duplicate display names lightly
            existing = {p["name"] for p in self.players.values()}
            base, n = name, 2
            while name in existing:
                name = f"{base} {n}"; n += 1
            self.players[pid] = {"name": name, "score": 0, "answered": False, "lastGain": 0,
                                 "nCorrect": 0, "tSum": 0}
        self.broadcast()
        return pid, name

    def answer(self, pid, idx=None, text=None):
        with self.lock:
            if self.phase != "question" or pid not in self.players:
                return
            if pid in self.answers:
                return  # already answered
            Q = QUESTIONS[self.qIndex]
            now = int(time.time() * 1000)
            used = max(0, now - self.startTime)
            limit = Q["time"] * 1000
            if Q["type"] == "open":
                t = (text or "").strip()[:250]
                if not t:
                    return
                self.answers[pid] = {"text": t, "t": used, "correct": None, "points": OPEN_POINTS}
                self.open_responses.append({"name": self.players[pid]["name"], "text": t})
                self.players[pid]["score"] += OPEN_POINTS
                self.players[pid]["lastGain"] = OPEN_POINTS
            else:
                if idx is None or not (0 <= idx < len(Q["options"])):
                    return
                correct = (idx == Q["correct"])
                if correct:
                    frac = min(1.0, used / limit) if limit else 1.0
                    points = int(round(1000 * (1 - frac / 2)))
                else:
                    points = 0
                self.answers[pid] = {"idx": idx, "t": used, "correct": correct, "points": points}
                self.players[pid]["score"] += points
                self.players[pid]["lastGain"] = points
                if correct:
                    self.players[pid]["nCorrect"] += 1
                    self.players[pid]["tSum"] += used
        self.broadcast()

    # -- host actions --
    def start_question(self, i):
        with self.lock:
            self.qIndex = i
            self.phase = "question"
            self.startTime = int(time.time() * 1000)
            self.paused = False
            self.answers = {}
            self.open_responses = []
            for p in self.players.values():
                p["lastGain"] = 0
        self.broadcast()

    def _enter_reveal(self):
        # assumes self.lock is held
        self.phase = "reveal"
        self.revealTime = int(time.time() * 1000)
        # auto-pause on the open-ended results so the host can read the answers
        self.paused = (0 <= self.qIndex < len(QUESTIONS)
                       and QUESTIONS[self.qIndex]["type"] == "open")

    def host_next(self):
        with self.lock:
            phase, i = self.phase, self.qIndex
        if phase == "lobby":
            self.start_question(0)
        elif phase == "question":
            with self.lock:
                self._enter_reveal()
            self.broadcast()
        elif phase == "reveal":
            if i + 1 < len(QUESTIONS):
                self.start_question(i + 1)
            else:
                with self.lock:
                    self.phase = "podium"
                self.broadcast()
        elif phase == "podium":
            pass

    def host_reveal(self):
        with self.lock:
            if self.phase == "question":
                self._enter_reveal()
        self.broadcast()

    def host_pause(self):
        # toggle the auto-advance pause on the results screen
        with self.lock:
            if self.phase == "reveal":
                self.paused = not self.paused
                if not self.paused:
                    self.revealTime = int(time.time() * 1000)  # restart the countdown
        self.broadcast()

    def host_back(self):
        # go back one question (host correction)
        with self.lock:
            i = self.qIndex
        if i > 0:
            self.start_question(i - 1)
        else:
            with self.lock:
                self.phase = "lobby"; self.qIndex = -1
            self.broadcast()

    def reset(self):
        # Fresh game: clear everyone out so old names don't linger; players rejoin.
        with self.lock:
            self.phase = "lobby"; self.qIndex = -1; self.answers = {}
            self.open_responses = []
            self.players = {}
            self.paused = False
        self.broadcast()

    def results_duration(self):
        if 0 <= self.qIndex < len(QUESTIONS) and QUESTIONS[self.qIndex]["type"] == "open":
            return OPEN_RESULTS_MS
        return MC_RESULTS_MS

    def auto_tick(self):
        # 1) auto-reveal when time runs out or everyone has answered
        # 2) auto-advance to the next question after the results screen has shown
        # Wrapped so a stray error can never kill the game loop.
        while True:
            time.sleep(0.5)
            try:
                do_reveal = False
                do_advance = False
                with self.lock:
                    now = int(time.time() * 1000)
                    if self.phase == "question" and 0 <= self.qIndex < len(QUESTIONS):
                        Q = QUESTIONS[self.qIndex]
                        over = (now - self.startTime) >= Q["time"] * 1000
                        everyone = len(self.players) > 0 and len(self.answers) >= len(self.players)
                        do_reveal = over or everyone
                    elif self.phase == "reveal":
                        do_advance = (not self.paused) and (now - self.revealTime) >= self.results_duration()
                if do_reveal:
                    self.host_reveal()
                elif do_advance:
                    self.host_next()
            except Exception:
                pass


GAME = Game()


# ----------------------------------------------------------------------------
# HTTP handler
# ----------------------------------------------------------------------------
def get_lan_ip():
    ip = "127.0.0.1"
    try:
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        ip = s.getsockname()[0]
        s.close()
    except Exception:
        try:
            ip = socket.gethostbyname(socket.gethostname())
        except Exception:
            pass
    return ip


def read_file(name):
    p = os.path.join(BASE_DIR, name)
    if os.path.exists(p):
        with open(p, "rb") as f:
            return f.read()
    return _b64.b64decode(_EMBEDDED[name])


class Handler(http.server.BaseHTTPRequestHandler):
    protocol_version = "HTTP/1.1"

    def log_message(self, *args):
        pass  # quiet

    def _send(self, code, body, ctype="application/json", extra=None):
        if isinstance(body, str):
            body = body.encode("utf-8")
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(body)))
        self.send_header("Cache-Control", "no-store")
        if extra:
            for k, v in extra.items():
                self.send_header(k, v)
        self.end_headers()
        try:
            self.wfile.write(body)
        except Exception:
            pass

    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path
        qs = parse_qs(parsed.query)

        if path in ("/", "/host", "/host.html"):
            return self._send(200, read_file("host.html"), "text/html; charset=utf-8")
        if path in ("/play", "/player", "/player.html"):
            return self._send(200, read_file("player.html"), "text/html; charset=utf-8")
        if path == "/config":
            ip = get_lan_ip()
            lan = f"http://{ip}:{PORT}/play"
            join = (PUBLIC_URL + "/play") if PUBLIC_URL else lan
            cfg = {"ip": ip, "port": PORT, "lanUrl": lan, "joinUrl": join,
                   "public": bool(PUBLIC_URL), "total": len(QUESTIONS)}
            return self._send(200, json.dumps(cfg))
        if path == "/state":
            pid = qs.get("id", [""])[0]
            return self._send(200, json.dumps(GAME.state_for(pid)))
        if path == "/events":
            return self.handle_sse(qs)
        return self._send(404, json.dumps({"error": "not found"}))

    def handle_sse(self, qs):
        role = qs.get("role", ["player"])[0]
        pid = qs.get("id", [""])[0]
        sub = GAME.subscribe(role, pid)
        try:
            self.send_response(200)
            self.send_header("Content-Type", "text/event-stream")
            self.send_header("Cache-Control", "no-cache")
            self.send_header("Connection", "keep-alive")
            self.send_header("X-Accel-Buffering", "no")
            self.end_headers()
            # initial state
            self.wfile.write(b": connected\n\n")
            self.wfile.write(("data: " + json.dumps(GAME.state_for(pid)) + "\n\n").encode())
            self.wfile.flush()
            while True:
                try:
                    msg = sub["q"].get(timeout=15)
                    self.wfile.write(("data: " + json.dumps(msg) + "\n\n").encode())
                    self.wfile.flush()
                except queue.Empty:
                    self.wfile.write(b": keepalive\n\n")
                    self.wfile.flush()
        except Exception:
            pass
        finally:
            GAME.unsubscribe(sub)

    def do_POST(self):
        parsed = urlparse(self.path)
        path = parsed.path
        length = int(self.headers.get("Content-Length", "0") or "0")
        raw = self.rfile.read(length) if length else b"{}"
        try:
            data = json.loads(raw.decode("utf-8") or "{}")
        except Exception:
            data = {}

        if path == "/join":
            pid, name = GAME.join(data.get("name", ""))
            return self._send(200, json.dumps({"id": pid, "name": name}))
        if path == "/answer":
            pid = data.get("id", "")
            if "idx" in data and data["idx"] is not None:
                GAME.answer(pid, idx=int(data["idx"]))
            else:
                GAME.answer(pid, text=data.get("text", ""))
            return self._send(200, json.dumps({"ok": True}))
        if path == "/host":
            action = data.get("action", "")
            if action == "next":
                GAME.host_next()
            elif action == "reveal":
                GAME.host_reveal()
            elif action == "back":
                GAME.host_back()
            elif action == "reset":
                GAME.reset()
            elif action == "start":
                GAME.start_question(0)
            elif action == "pause":
                GAME.host_pause()
            return self._send(200, json.dumps({"ok": True}))
        return self._send(404, json.dumps({"error": "not found"}))


class ThreadingHTTPServer(socketserver.ThreadingMixIn, http.server.HTTPServer):
    daemon_threads = True
    request_queue_size = 128   # absorb a burst of phones connecting at once
    allow_reuse_address = True


def tunnel_enabled():
    # Try to create a public link locally; on a cloud host the platform already
    # provides one, so skip it. Opt out anywhere with QUIZ_NO_TUNNEL=1.
    return not os.environ.get("QUIZ_NO_TUNNEL") and not ON_PLATFORM


def cloudflared_path():
    """Find cloudflared on this machine; if it's missing, download the right build
    for this OS automatically (one-time). Returns a path or None."""
    p = shutil.which("cloudflared")
    if p:
        return p
    for c in ("/opt/homebrew/bin/cloudflared", "/usr/local/bin/cloudflared",
              "/usr/bin/cloudflared"):
        if os.path.exists(c):
            return c
    local = os.path.join(BASE_DIR, "cloudflared.exe" if os.name == "nt" else "cloudflared")
    if os.path.exists(local):
        return local
    return _download_cloudflared(local)


def _download_cloudflared(dest):
    import platform, urllib.request, tarfile
    sysname = platform.system().lower()
    machine = platform.machine().lower()
    is_arm = "arm" in machine or "aarch64" in machine
    base = "https://github.com/cloudflare/cloudflared/releases/latest/download/"
    print("  First-time setup: downloading the public-link helper (cloudflared)…")
    print("  (one-time, ~30 seconds, needs internet)")
    try:
        if sysname == "darwin":
            url = base + ("cloudflared-darwin-arm64.tgz" if is_arm else "cloudflared-darwin-amd64.tgz")
            tmp, _ = urllib.request.urlretrieve(url)
            with tarfile.open(tmp) as t:
                member = next(m for m in t.getmembers() if m.name.endswith("cloudflared"))
                with t.extractfile(member) as src, open(dest, "wb") as out:
                    out.write(src.read())
            os.chmod(dest, 0o755)
            return dest
        if sysname == "windows":
            urllib.request.urlretrieve(base + "cloudflared-windows-amd64.exe", dest)
            return dest
        if sysname == "linux":
            url = base + ("cloudflared-linux-arm64" if is_arm else "cloudflared-linux-amd64")
            urllib.request.urlretrieve(url, dest)
            os.chmod(dest, 0o755)
            return dest
    except Exception as e:
        print("  (Could not set up the public link automatically:", e, ")")
        print("  The quiz still works for phones on the SAME Wi-Fi.")
    return None


def _read_tunnel_output(proc):
    """Watch cloudflared's output for the public https URL and publish it."""
    global PUBLIC_URL
    pat = re.compile(r"https://[-a-z0-9]+\.trycloudflare\.com")
    for line in proc.stdout:
        m = pat.search(line)
        if m and not PUBLIC_URL:
            PUBLIC_URL = m.group(0)
            print("\n  PLAYERS (ANY network)  :  " + PUBLIC_URL + "/play")
            print("  ^ the QR on the big screen now uses this — works on mobile data too.\n")


def start_tunnel(port):
    """Expose the local server on a public https URL via a free Cloudflare quick
    tunnel (no account needed), so phones can join from any network. Falls back
    silently to same-Wi-Fi only if cloudflared is missing or there's no internet.
    Disable with QUIZ_NO_TUNNEL=1."""
    global _tunnel_proc
    exe = cloudflared_path()
    if not exe:
        print("  (No public link — phones must be on the SAME Wi-Fi as this laptop.)")
        return
    try:
        _tunnel_proc = subprocess.Popen(
            [exe, "tunnel", "--no-autoupdate", "--url", f"http://localhost:{port}"],
            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
            text=True, bufsize=1,
        )
    except Exception:
        return
    atexit.register(stop_tunnel)
    threading.Thread(target=_read_tunnel_output, args=(_tunnel_proc,), daemon=True).start()


def stop_tunnel():
    global _tunnel_proc
    if _tunnel_proc:
        try:
            _tunnel_proc.terminate()
        except Exception:
            pass
        _tunnel_proc = None


def main():
    global PORT
    threading.Thread(target=GAME.auto_tick, daemon=True).start()
    ip = get_lan_ip()
    # bind: on a platform use exactly $PORT; locally walk up if 8000 is busy
    server = None
    candidates = [PORT] if ON_PLATFORM else range(PORT, PORT + 20)
    for p in candidates:
        try:
            server = ThreadingHTTPServer(("0.0.0.0", p), Handler)
            PORT = p
            break
        except OSError:
            continue
    if server is None:
        print("Could not find a free port. Close other apps and try again.")
        return
    print("\n" + "=" * 56)
    print("  WSTI QUIZ is running!  (press Ctrl+C to stop)")
    print("=" * 56)
    print(f"\n  BIG SCREEN (this laptop):  http://localhost:{PORT}/host")
    print(f"\n  PLAYERS on same Wi-Fi   :  http://{ip}:{PORT}/play")
    if tunnel_enabled():
        print("\n  Creating a public link so phones on ANY network can join…")
        print("  (needs internet on this laptop; takes a few seconds)")
    else:
        print("\n  (Phones must be on the SAME Wi-Fi as this laptop.)")
    print("=" * 56 + "\n")
    if tunnel_enabled():
        # run in the background (may download cloudflared on first use) so the
        # big-screen page is usable immediately; the QR updates when it's ready
        threading.Thread(target=start_tunnel, args=(PORT,), daemon=True).start()
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nStopped. Thanks for playing!")
    finally:
        stop_tunnel()


if __name__ == "__main__":
    main()
